import json
from typing import Any, Optional

def decode_and_verify_jwt(token: str) -> Optional[dict]:
    """Decode and verify a JWT token for debugging purposes.

    Args:
        token (str): The JWT token to be decoded and verified.

    Returns:
        dict: The payload of the JWT token, or None if the token is invalid.
    """
    import jwt

    try:
        payload = jwt.decode(token, algorithms=["HS256"])
        return payload
    except jwt.InvalidTokenError as e:
        print(f"Invalid JWT token: {e}")
        return None